import React, { useState, useEffect, useMemo } from "react";
import { supabase } from '../../supabaseClient';
import { useDocuments } from "../../hooks/useDocuments";
import type { DocumentFormData, DocumentStatus } from "./document";
import { STATUS_LABELS } from "./document";
import FileUpload from './FileUpload';
import DiffViewer from './DiffViewer';

const Documents: React.FC = () => {
  const {
    documents,
    loading,
    error,
    documentVersions,
    createDocument,
    updateDocumentWithVersioning,
    fetchDocumentVersions,
    restoreDocumentVersion,
    deleteDocuments,
  } = useDocuments();

  // États
  const [searchTerm, setSearchTerm] = useState<string>("");
  const [statusFilter, setStatusFilter] = useState<string>("Tous");
  const [typeFilter, setTypeFilter] = useState<string>("Tous");
  const [isModalOpen, setIsModalOpen] = useState<boolean>(false);
  const [isHistoryModalOpen, setIsHistoryModalOpen] = useState<boolean>(false);
  const [editingDocument, setEditingDocument] = useState<any>(null);
  const [selectedDocumentForHistory, setSelectedDocumentForHistory] = useState<string | null>(null);
  const [contextMenuOpen, setContextMenuOpen] = useState<string | null>(null);
  const [diffViewerOpen, setDiffViewerOpen] = useState(false);
  const [versionsToCompare, setVersionsToCompare] = useState<{ old: any; new: any } | null>(null);
  const [statusMenuOpen, setStatusMenuOpen] = useState(false);
  const [assigneeMenuOpen, setAssigneeMenuOpen] = useState(false);
  const [newDocument, setNewDocument] = useState<DocumentFormData>({
    title: "",
    type: "Transcription",
    source: "",
    status: "imported",
    progress: 0,
    assigned_to: "",
    tags: [],
    file_url: "",
  });
  const [formErrors, setFormErrors] = useState({
    title: false,
    source: false,
    assigned_to: false,
  });
  const [tagsInput, setTagsInput] = useState<string>("");
  const [selectedDocuments, setSelectedDocuments] = useState<string[]>([]);

  // 🔑 Pagination (6 documents par page)
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6;

  // Options métier
  const documentTypes = ["Transcription", "Audio", "Édition", "Vidéo", "Image"];
  const documentStatuses: DocumentStatus[] = [
    'imported',
    'transcribing',
    'transcribed',
    'reviewing',
    'reviewed',
    'tagging',
    'tagged',
    'editing',
    'edited'
  ];
  const assignees = ["Non assigné", "Marie Dubois", "Thomas Martin", "Sophie Laurent", "Paul Morel", "Jean Dupont"];

  // Fermer menu au clic extérieur
  useEffect(() => {
    const handleClickOutside = (e: MouseEvent) => {
      const target = e.target as HTMLElement;
      if (!target.closest('.context-menu-button') && !target.closest('.context-menu')) {
        setContextMenuOpen(null);
      }
      // 🔑 Fermer les menus bulk actions
      if (!target.closest('[data-bulk-menu]')) {
        setStatusMenuOpen(false);
        setAssigneeMenuOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  // 🔑 FILTRAGE ÉTENDU (titre, source, assigné, tags, contenu)
  const filteredDocuments = useMemo(() => {
    return documents.filter((doc: any) => {
      const searchLower = searchTerm.toLowerCase().trim();

      // Recherche dans tous les champs pertinents
      const searchableFields = [
        doc.title,
        doc.source,
        doc.assigned_to,
        ...(doc.tags || []),
        doc.content,
        doc.status,
        doc.id,
      ].filter(Boolean).map(f => String(f).toLowerCase());

      const matchesSearch = searchLower === "" ||
        searchableFields.some(field => field.includes(searchLower));

      const matchesStatus = statusFilter === "Tous" || doc.status === statusFilter;
      const matchesType = typeFilter === "Tous" || doc.type === typeFilter;

      return matchesSearch && matchesStatus && matchesType;
    });
  }, [documents, searchTerm, statusFilter, typeFilter]);

  // 🔑 PAGINATION
  const paginatedDocuments = useMemo(() => {
    const startIndex = (currentPage - 1) * itemsPerPage;
    return filteredDocuments.slice(startIndex, startIndex + itemsPerPage);
  }, [filteredDocuments, currentPage, itemsPerPage]);

  const totalPages = Math.ceil(filteredDocuments.length / itemsPerPage);

  const uniqueStatuses = useMemo(() => {
    const statuses = ["Tous", ...new Set(documents.map((doc: any) => doc.status))];
    return statuses;
  }, [documents]);

  const uniqueTypes = useMemo(() => {
    const types = ["Tous", ...new Set(documents.map((doc: any) => doc.type))];
    return types;
  }, [documents]);

  // Gestion de la sélection multiple
  const toggleDocumentSelection = (documentId: string) => {
    setSelectedDocuments(prev =>
      prev.includes(documentId)
        ? prev.filter(id => id !== documentId)
        : [...prev, documentId]
    );
  };

  const toggleSelectAll = () => {
    if (selectedDocuments.length === paginatedDocuments.length && paginatedDocuments.length > 0) {
      setSelectedDocuments([]);
    } else {
      setSelectedDocuments(paginatedDocuments.map((doc: any) => doc.id));
    }
  };

  // Suppression multiple
  const handleDeleteSelected = async () => {
    if (selectedDocuments.length === 0) return;
    const confirmation = window.confirm(
      `Êtes-vous sûr de vouloir supprimer ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} ?\nCette action est irréversible.`
    );
    if (confirmation) {
      try {
        await deleteDocuments(selectedDocuments);
        alert(`✅ ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} supprimé${selectedDocuments.length > 1 ? 's' : ''} avec succès !`);
        setSelectedDocuments([]);
      } catch (err) {
        console.error('Erreur suppression:', err);
        alert('❌ Erreur suppression');
      }
    }
  };

  // Bulk actions - Changer statut
  const handleBulkStatusChange = async (newStatus: DocumentStatus) => {
    if (selectedDocuments.length === 0) return;

    const confirmation = window.confirm(
      `Changer le statut de ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} en "${STATUS_LABELS[newStatus]}" ?`
    );

    if (confirmation) {
      try {
        await Promise.all(
          selectedDocuments.map(id => {
            const doc = documents.find(d => d.id === id);
            return doc ? updateDocumentWithVersioning(id, {
              ...doc,
              status: newStatus,
              workflow_step: getWorkflowStep(newStatus),
              progress: getWorkflowProgress(newStatus)
            }) : Promise.resolve();
          })
        );
        alert(`✅ Statut mis à jour pour ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''}`);
        setSelectedDocuments([]);
      } catch (err) {
        console.error('Erreur changement statut:', err);
        alert('❌ Erreur lors du changement de statut');
      }
    }
  };

  // Bulk actions - Réassigner (CORRIGÉ)
  const handleBulkReassign = async (newAssignee: string) => {
    if (selectedDocuments.length === 0 || !newAssignee) return;

    const confirmation = window.confirm(
      `Réassigner ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} à "${newAssignee}" ?`
    );

    if (confirmation) {
      try {
        await Promise.all(
          selectedDocuments.map(id => {
            const doc = documents.find(d => d.id === id);
            return doc ? updateDocumentWithVersioning(id, { ...doc, assigned_to: newAssignee }) : Promise.resolve();
          })
        );
        alert(`✅ ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''} réassigné${selectedDocuments.length > 1 ? 's' : ''} à ${newAssignee}`);
        setSelectedDocuments([]);
        setAssigneeMenuOpen(false);
      } catch (err) {
        console.error('Erreur réassignation:', err);
        alert('❌ Erreur lors de la réassignation');
      }
    }
  };

  // Gestion de l'édition
  const handleEditDocument = (doc: any) => {
    setEditingDocument(doc);
    setNewDocument({
      title: doc.title,
      type: doc.type,
      source: doc.source,
      status: doc.status,
      progress: doc.progress,
      assigned_to: doc.assigned_to,
      tags: doc.tags || [],
      file_url: doc.file_url || '',
    });
    setTagsInput('');
    setIsModalOpen(true);
  };

  // Gestion des tags
  const handleAddTag = () => {
    const tag = tagsInput.trim();
    if (tag && !newDocument.tags?.includes(tag)) {
      setNewDocument(prev => ({
        ...prev,
        tags: [...(prev.tags || []), tag]
      }));
      setTagsInput('');
    }
  };

  const handleRemoveTag = (tagToRemove: string) => {
    setNewDocument(prev => ({
      ...prev,
      tags: (prev.tags || []).filter(tag => tag !== tagToRemove)
    }));
  };

  // Validation du formulaire
  const validateForm = () => {
    const newErrors = {
      title: newDocument.title.trim() === "",
      source: newDocument.source.trim() === "",
      assigned_to: newDocument.assigned_to === "",
    };
    setFormErrors(newErrors);
    return !newErrors.title && !newErrors.source && !newErrors.assigned_to;
  };

  // Soumission du formulaire
  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;
    try {
      if (editingDocument) {
        await updateDocumentWithVersioning(editingDocument.id, newDocument);
        alert("✅ Document mis à jour avec succès !\nUne nouvelle version a été sauvegardée.");
      } else {
        await createDocument(newDocument);
        alert("✅ Document créé avec succès !");
      }
      setEditingDocument(null);
      setIsModalOpen(false);
      setNewDocument({
        title: "",
        type: "Transcription",
        source: "",
        status: "imported",
        progress: 0,
        assigned_to: "",
        tags: [],
        file_url: ""
      });
      setFormErrors({ title: false, source: false, assigned_to: false });
      setTagsInput('');
    } catch (err: any) {
      console.error(editingDocument ? 'Erreur mise à jour:' : 'Erreur création:', err);
      const errorMessage = err instanceof Error ? err.message : String(err);
      if (errorMessage.includes('Non authentifié')) {
        await supabase.auth.signOut();
        alert("🔒 Session invalide. Redirection...");
        window.location.href = "/login";
        return;
      }
      alert(editingDocument
        ? `❌ Erreur mise à jour:\n${errorMessage}`
        : `❌ Erreur création:\n${errorMessage}`
      );
    }
  };

  // Menu contextuel
  const toggleContextMenu = (documentId: string) => {
    setContextMenuOpen(prev => prev === documentId ? null : documentId);
  };

  const handleExportPDF = (doc: any) => {
    setContextMenuOpen(null);
    alert(`📄 Export PDF pour "${doc.title}"\n(Utilisez Ctrl+P pour imprimer en PDF)`);
  };

  const handleShareDocument = (doc: any) => {
    setContextMenuOpen(null);
    const shareUrl = `${window.location.origin}/documents/${doc.id}`;
    navigator.clipboard.writeText(shareUrl).then(() => {
      alert(`🔗 Lien copié :\n${shareUrl}`);
    });
  };

  const handleDuplicateDocument = async (doc: any) => {
    setContextMenuOpen(null);
    if (window.confirm(`Dupliquer "${doc.title}" ?`)) {
      try {
        await createDocument({
          title: `${doc.title} (copie)`,
          type: doc.type,
          source: doc.source,
          status: "imported",
          progress: 0,
          assigned_to: doc.assigned_to,
          tags: [...(doc.tags || [])],
          file_url: doc.file_url || ''
        });
        alert("✅ Document dupliqué !");
      } catch (err) {
        alert("❌ Erreur duplication");
      }
    }
  };

  const handleShowStats = (doc: any) => {
    setContextMenuOpen(null);
    const days = Math.floor((new Date().getTime() - new Date(doc.created_at).getTime()) / (1000 * 60 * 60 * 24));
    alert(`📊 "${doc.title}"\n• Créé il y a ${days} jour${days > 1 ? 's' : ''}\n• ${doc.tags?.length || 0} tags\n• Statut: ${STATUS_LABELS[doc.status as DocumentStatus]}`);
  };

  const handleOpenHistory = async (documentId: string) => {
    setContextMenuOpen(null);
    setSelectedDocumentForHistory(documentId);
    await fetchDocumentVersions(documentId);
    setIsHistoryModalOpen(true);
  };

  const handleRestoreVersion = async (versionId: string) => {
    const reason = prompt("Raison de la restauration (optionnel) :");
    if (selectedDocumentForHistory) {
      try {
        await restoreDocumentVersion(selectedDocumentForHistory, versionId, reason || 'Restauration manuelle');
        alert("✅ Version restaurée !");
        setIsHistoryModalOpen(false);
      } catch (err) {
        alert("❌ Erreur restauration");
      }
    }
  };

  // Comparaison de versions
  const handleCompareVersions = (newVersion: any) => {
    const currentIndex = documentVersions.findIndex((v: any) => v.id === newVersion.id);
    if (currentIndex < documentVersions.length - 1) {
      const oldVersion = documentVersions[currentIndex + 1];
      setVersionsToCompare({ old: oldVersion, new: newVersion });
      setDiffViewerOpen(true);
    } else {
      alert("ℹ️ Cette version est la plus ancienne disponible.\nImpossible de comparer avec une version précédente.");
    }
  };

  // Fonctions utilitaires
  const closeModal = () => {
    setIsModalOpen(false);
    setEditingDocument(null);
    setNewDocument({
      title: "",
      type: "Transcription",
      source: "",
      status: "imported",
      progress: 0,
      assigned_to: "",
      tags: [],
      file_url: ""
    });
    setFormErrors({ title: false, source: false, assigned_to: false });
    setTagsInput('');
    setContextMenuOpen(null);
  };

  const closeHistoryModal = () => {
    setIsHistoryModalOpen(false);
    setSelectedDocumentForHistory(null);
  };

  const formatDate = (dateString: string): string => {
    try {
      return new Intl.DateTimeFormat('fr-FR', { year: 'numeric', month: 'long', day: 'numeric' }).format(new Date(dateString));
    } catch { return dateString; }
  };

  const formatDateTime = (dateString: string): string => {
    try {
      return new Intl.DateTimeFormat('fr-FR', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }).format(new Date(dateString));
    } catch { return dateString; }
  };

  const statusClass = (status: string) => {
    switch (status) {
      case "edited": return "text-purple-800 bg-purple-100 dark:bg-purple-900 dark:text-purple-200";
      case "editing": return "text-blue-800 bg-blue-100 dark:bg-blue-900 dark:text-blue-200";
      case "tagged": return "text-green-800 bg-green-100 dark:bg-green-900 dark:text-green-200";
      case "tagging": return "text-indigo-800 bg-indigo-100 dark:bg-indigo-900 dark:text-indigo-200";
      case "reviewed": return "text-amber-800 bg-amber-100 dark:bg-amber-900 dark:text-amber-200";
      case "reviewing": return "text-yellow-800 bg-yellow-100 dark:bg-yellow-900 dark:text-yellow-200";
      case "transcribed": return "text-emerald-800 bg-emerald-100 dark:bg-emerald-900 dark:text-emerald-200";
      case "transcribing": return "text-cyan-800 bg-cyan-100 dark:bg-cyan-900 dark:text-cyan-200";
      case "imported": return "text-gray-800 bg-gray-100 dark:bg-gray-700 dark:text-gray-200";
      default: return "text-gray-500 bg-gray-100 dark:bg-gray-700";
    }
  };

  const getWorkflowStep = (status: DocumentStatus): 1 | 2 | 3 | 4 | 5 => {
    const steps: Record<DocumentStatus, 1 | 2 | 3 | 4 | 5> = {
      'imported': 1,
      'transcribing': 2,
      'transcribed': 2,
      'reviewing': 3,
      'reviewed': 3,
      'tagging': 4,
      'tagged': 4,
      'editing': 5,
      'edited': 5
    };
    return steps[status];
  };

  const getWorkflowProgress = (status: DocumentStatus): number => {
    switch (status) {
      case 'imported': return 0;
      case 'transcribing': return 20;
      case 'transcribed': return 40;
      case 'reviewing': return 40;
      case 'reviewed': return 60;
      case 'tagging': return 60;
      case 'tagged': return 80;
      case 'editing': return 80;
      case 'edited': return 100;
      default: return 0;
    }
  };

  // Rendu JSX
  return (
    <div className="container mx-auto px-4 py-4 h-full flex flex-col">
      {/* Barre d'outils */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow mb-4 p-4 z-10">
        <div className="flex flex-col md:flex-row gap-4">
          <div className="flex-1">
            <div className="relative">
              <input
                id="search-documents"
                type="text"
                value={searchTerm}
                onChange={(e) => {
                  setSearchTerm(e.target.value);
                  setCurrentPage(1);
                }}
                className="w-full pl-10 pr-4 py-2 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent dark:bg-gray-700 dark:text-white"
                placeholder="Rechercher (titre, source, assigné, tags, contenu)..."
              />
              <i className="fas fa-search absolute left-3 top-1/2 transform -translate-y-1/2 text-gray-400"></i>
            </div>
          </div>
          <div className="flex gap-3 flex-wrap md:flex-nowrap">
            <div className="w-full md:w-auto">
              <select
                value={statusFilter}
                onChange={(e) => {
                  setStatusFilter(e.target.value);
                  setCurrentPage(1);
                }}
                className="w-full md:w-auto py-2 px-3 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent dark:bg-gray-700 dark:text-white"
              >
                <option value="Tous">Tous les statuts</option>
                {documentStatuses.map((status) => (
                  <option key={status} value={status}>
                    {STATUS_LABELS[status]}
                  </option>
                ))}
              </select>
            </div>
            <div className="w-full md:w-auto">
              <select
                value={typeFilter}
                onChange={(e) => {
                  setTypeFilter(e.target.value);
                  setCurrentPage(1);
                }}
                className="w-full md:w-auto py-2 px-3 text-base border border-gray-300 dark:border-gray-700 rounded-md focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent dark:bg-gray-700 dark:text-white"
              >
                {uniqueTypes.map((type: any) => (
                  <option key={type} value={type}>
                    {type === "Tous" ? "Tous les types" : type}
                  </option>
                ))}
              </select>
            </div>
            <button
              onClick={() => { setEditingDocument(null); setIsModalOpen(true); }}
              className="flex-none px-4 py-2 bg-primary hover:bg-primary-dark text-white rounded-md transition-colors flex items-center"
            >
              <i className="fas fa-plus mr-2"></i> Nouveau document
            </button>
          </div>
        </div>
      </div>

      {/* Statistiques et sélection */}
      <div className="mb-4 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3">
        <p className="text-sm text-gray-600 dark:text-gray-400">
          <strong>{paginatedDocuments.length}</strong> document{paginatedDocuments.length > 1 ? 's' : ''} affiché{paginatedDocuments.length > 1 ? 's' : ''} sur <strong>{filteredDocuments.length}</strong> filtré{filteredDocuments.length > 1 ? 's' : ''} (total: <strong>{documents.length}</strong>)
        </p>
        {paginatedDocuments.length > 0 && (
          <div className="flex items-center gap-2">
            <label className="flex items-center text-sm text-gray-600 dark:text-gray-400 cursor-pointer">
              <input
                type="checkbox"
                checked={paginatedDocuments.length > 0 && selectedDocuments.length === paginatedDocuments.length}
                onChange={toggleSelectAll}
                className="w-4 h-4 text-primary border-gray-300 rounded focus:ring-primary dark:bg-gray-700 dark:border-gray-600"
              />
              <span className="ml-2">Sélectionner tout</span>
            </label>
            {selectedDocuments.length > 0 && (
              <span className="text-xs font-medium text-primary bg-primary/10 dark:bg-primary/20 px-2.5 py-1 rounded-full">
                {selectedDocuments.length} sélectionné{selectedDocuments.length > 1 ? 's' : ''}
              </span>
            )}
          </div>
        )}
      </div>

      {/* Message d'erreur */}
      {error && (
        <div className="mb-4 p-4 bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-300 rounded-lg">
          <i className="fas fa-exclamation-triangle mr-2"></i>
          {error}
        </div>
      )}

      {/* Cadre documents */}
      <div className="bg-white dark:bg-gray-800 rounded-lg shadow flex-1 overflow-hidden border border-gray-200 dark:border-gray-700">
        <div className="bg-gray-50 dark:bg-gray-700/50 px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-3">
          <h2 className="font-semibold text-gray-800 dark:text-gray-200 text-lg flex items-center">
            <i className="fas fa-book-open mr-2 text-primary"></i>
            Bibliothèque éditoriale
          </h2>

          {/* 🔑 BOUTON SUPPRIMER DANS L'EN-TÊTE */}
          {selectedDocuments.length > 0 && (
            <button
              onClick={handleDeleteSelected}
              className="group px-4 py-2 bg-gradient-to-r from-red-500 to-red-600 text-white font-medium rounded-lg flex items-center gap-2 hover:from-red-600 hover:to-red-700 transition-all"
              title={`Supprimer ${selectedDocuments.length} document${selectedDocuments.length > 1 ? 's' : ''}`}
            >
              <i className="fas fa-trash-alt"></i>
              <span className="hidden sm:inline">Supprimer</span>
              <span className="ml-1 bg-red-700 text-white text-xs font-bold px-2 py-0.5 rounded-full">
                {selectedDocuments.length}
              </span>
            </button>
          )}
        </div>

        <div className="overflow-y-auto h-full" style={{ maxHeight: 'calc(100vh - 280px)' }}>
          {loading ? (
            <div className="flex justify-center items-center h-64">
              <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary"></div>
            </div>
          ) : (
            <div className="p-6">
              <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
                {paginatedDocuments.length === 0 ? (
                  <div className="col-span-full py-16 text-center">
                    <div className="inline-block p-4 bg-gray-100 dark:bg-gray-700 rounded-full mb-4">
                      <i className="fas fa-search text-4xl text-gray-400"></i>
                    </div>
                    <p className="text-lg text-gray-600 dark:text-gray-300 font-medium mb-2">
                      Aucun document trouvé
                    </p>
                    {searchTerm && (
                      <button
                        onClick={() => setSearchTerm('')}
                        className="mt-4 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-md text-sm"
                      >
                        Effacer la recherche
                      </button>
                    )}
                  </div>
                ) : (
                  paginatedDocuments.map((doc: any) => (
                    <article
                      key={doc.id}
                      className={`relative bg-white dark:bg-gray-800 rounded-xl shadow-sm hover:shadow-md transition-shadow border ${selectedDocuments.includes(doc.id)
                        ? 'border-red-400 dark:border-red-500 ring-2 ring-red-200 dark:ring-red-900/50'
                        : 'border-gray-100 dark:border-gray-700'
                        }`}
                      role="listitem"
                    >
                      {/* Checkbox de sélection */}
                      <div
                        className="absolute top-3 right-3 z-10"
                        onClick={(e) => { e.stopPropagation(); toggleDocumentSelection(doc.id); }}
                      >
                        <div className={`flex items-center justify-center w-6 h-6 rounded-full cursor-pointer transition-colors ${selectedDocuments.includes(doc.id)
                          ? 'bg-red-100 border-2 border-red-500 dark:bg-red-900/40 dark:border-red-500'
                          : 'bg-white/90 dark:bg-gray-800 border border-gray-300 dark:border-gray-600 hover:border-red-400'
                          }`}>
                          {selectedDocuments.includes(doc.id) && (
                            <i className="fas fa-check text-red-500 dark:text-red-400 text-xs font-bold"></i>
                          )}
                        </div>
                      </div>
                      <div className="p-5 pt-8">
                        {/* Titre et statut */}
                        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-start mb-4">
                          <h3 className="font-bold text-gray-900 dark:text-white text-lg mb-1 sm:mb-0 line-clamp-2">
                            {doc.title}
                          </h3>
                          <span className={`px-3 py-1 text-sm font-medium rounded-full ${statusClass(doc.status)} whitespace-nowrap`}>
                            {STATUS_LABELS[doc.status as DocumentStatus]}
                          </span>
                        </div>

                        {/* Type et source */}
                        <div className="text-sm text-gray-600 dark:text-gray-400 mb-4">
                          <div className="flex flex-wrap gap-3">
                            <span className="flex items-center"><i className="fas fa-file-alt mr-1.5 text-gray-400 text-xs"></i> {doc.type}</span>
                            <span className="flex items-center"><i className="fas fa-bookmark mr-1.5 text-gray-400 text-xs"></i> {doc.source}</span>
                          </div>
                        </div>

                        {/* Workflow visuel */}
                        <div className="mb-4">
                          <div className="flex items-center justify-between text-xs text-gray-500 dark:text-gray-400 mb-1.5">
                            <span className="flex items-center">
                              <i className="fas fa-sync-alt mr-1.5 text-blue-500"></i>
                              Étape {getWorkflowStep(doc.status as DocumentStatus)} / 5
                            </span>
                            <span>{getWorkflowProgress(doc.status as DocumentStatus)}%</span>
                          </div>
                          <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2 overflow-hidden">
                            <div
                              className="h-full bg-gradient-to-r from-blue-500 to-indigo-600 transition-all duration-500"
                              style={{ width: `${getWorkflowProgress(doc.status as DocumentStatus)}%` }}
                            ></div>
                          </div>
                        </div>

                        {/* Progression */}
                        <div className="mb-4">
                          <div className="flex justify-between items-center mb-1.5">
                            <span className="text-xs text-gray-500 dark:text-gray-400 font-medium">Progression</span>
                            <span className="text-xs font-medium text-gray-700 dark:text-gray-300">{doc.progress}%</span>
                          </div>
                          <div className="w-full bg-gray-100 dark:bg-gray-700 rounded-full h-2 overflow-hidden">
                            <div
                              className="bg-primary rounded-full h-2 transition-all duration-300 ease-in-out"
                              style={{ width: `${doc.progress}%` }}
                            ></div>
                          </div>
                        </div>

                        {/* Assignation et date */}
                        <div className="flex flex-col sm:flex-row sm:justify-between sm:items-center mb-4 pt-3 border-t border-gray-100 dark:border-gray-700">
                          <div className="flex items-center mb-2 sm:mb-0">
                            <i className="fas fa-user mr-2 text-gray-400 text-xs"></i>
                            <span className="font-medium text-gray-700 dark:text-gray-300 text-sm">{doc.assigned_to}</span>
                          </div>
                          <time className="text-xs text-gray-500 dark:text-gray-400" dateTime={doc.updated_at}>
                            <i className="fas fa-clock mr-1 text-gray-400 text-xs"></i>
                            {formatDate(doc.updated_at)}
                          </time>
                        </div>

                        {/* Tags */}
                        <div className="mt-3 pt-3 border-t border-gray-100 dark:border-gray-700">
                          <div className="flex flex-wrap gap-1.5">
                            {doc.tags.map((tag: string, index: number) => (
                              <span key={`${doc.id}-tag-${index}`} className="px-2 py-0.5 text-xs bg-gray-100 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-md">
                                #{tag}
                              </span>
                            ))}
                            {doc.tags.length === 0 && <span className="text-xs text-gray-400 italic">Aucun tag</span>}
                          </div>
                        </div>

                        {/* Mini-timeline */}
                        <div className="mt-4 pt-3 border-t border-gray-100 dark:border-gray-700">
                          <div className="flex items-center text-xs text-gray-500 dark:text-gray-400 mb-2">
                            <i className="fas fa-history mr-1.5 text-amber-500"></i>
                            <span>Dernières modifications</span>
                          </div>
                          <div className="relative pl-3.5">
                            <div className="relative mb-2">
                              <div className="absolute left-0 top-1.5 w-2.5 h-2.5 bg-green-500 rounded-full border-2 border-white dark:border-gray-800"></div>
                              <div className="ml-4 bg-green-50 dark:bg-green-900/20 text-green-800 dark:text-green-200 px-2 py-1 rounded text-xs">
                                Version actuelle
                              </div>
                            </div>
                          </div>
                        </div>

                        {/* Boutons */}
                        <div className="mt-5 pt-4 border-t border-gray-100 dark:border-gray-700 flex flex-col sm:flex-row gap-2">
                          <button
                            onClick={() => handleEditDocument(doc)}
                            className="flex-1 px-3.5 py-2 text-sm bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-medium transition-colors flex items-center justify-center"
                            aria-label={`Modifier ${doc.title}`}
                          >
                            <i className="fas fa-pen mr-1.5"></i> Modifier
                          </button>

                          <div className="relative">
                            <button
                              onClick={(e) => { e.stopPropagation(); toggleContextMenu(doc.id); }}
                              className="context-menu-button px-3.5 py-2 text-sm bg-gray-100 hover:bg-gray-200 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-lg font-medium transition-colors flex items-center justify-center w-full sm:w-auto"
                              aria-label={`Options pour ${doc.title}`}
                              aria-expanded={contextMenuOpen === doc.id}
                            >
                              <i className="fas fa-ellipsis-v"></i>
                            </button>

                            {/* ✅ MENU CONTEXTUEL STABLE */}
                            {contextMenuOpen === doc.id && (
                              <div
                                className="context-menu absolute right-0 mt-1 w-56 bg-white dark:bg-gray-800 rounded-lg shadow-lg z-50 border border-gray-200 dark:border-gray-700 py-1"
                                role="menu"
                                onClick={(e) => e.stopPropagation()}
                              >
                                <button onClick={() => handleExportPDF(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50">
                                  <i className="fas fa-file-pdf mr-2.5 text-red-500"></i> Exporter en PDF
                                </button>
                                <button onClick={() => handleShareDocument(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50">
                                  <i className="fas fa-share-alt mr-2.5 text-blue-500"></i> Partager
                                </button>
                                <button onClick={() => handleDuplicateDocument(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50">
                                  <i className="fas fa-copy mr-2.5 text-green-500"></i> Dupliquer
                                </button>
                                <button onClick={() => handleShowStats(doc)} className="w-full flex items-center px-3.5 py-2 text-sm hover:bg-gray-100 dark:hover:bg-gray-700/50">
                                  <i className="fas fa-chart-line mr-2.5 text-purple-500"></i> Statistiques
                                </button>
                                <div className="h-px bg-gray-200 dark:bg-gray-700 my-1"></div>
                                <button onClick={() => handleOpenHistory(doc.id)} className="w-full flex items-center px-3.5 py-2 text-sm text-amber-700 dark:text-amber-400 hover:bg-amber-50 dark:hover:bg-amber-900/20">
                                  <i className="fas fa-history mr-2.5 text-amber-500"></i> Historique complet
                                </button>
                              </div>
                            )}
                          </div>
                        </div>
                      </div>
                    </article>
                  ))
                )}
              </div>
            </div>
          )}
        </div>
      </div>

      {/* Pagination */}
      {totalPages > 1 && (
        <div className="mt-6 flex flex-col sm:flex-row sm:justify-between sm:items-center gap-4">
          <p className="text-sm text-gray-600 dark:text-gray-400">
            Page {currentPage} sur {totalPages} • {filteredDocuments.length} résultat{filteredDocuments.length > 1 ? 's' : ''} filtré{filteredDocuments.length > 1 ? 's' : ''}
          </p>

          <div className="flex items-center gap-2">
            <button
              onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
              disabled={currentPage === 1}
              className="px-3 py-1.5 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 dark:hover:bg-gray-700"
            >
              <i className="fas fa-chevron-left"></i>
            </button>

            {[...Array(Math.min(5, totalPages))].map((_, i) => {
              const pageNum = Math.max(1, currentPage - 2) + i;
              if (pageNum > totalPages) return null;

              return (
                <button
                  key={pageNum}
                  onClick={() => setCurrentPage(pageNum)}
                  className={`px-3 py-1.5 rounded-lg text-sm font-medium ${currentPage === pageNum
                    ? 'bg-primary text-white'
                    : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                    }`}
                >
                  {pageNum}
                </button>
              );
            })}

            {totalPages > 5 && currentPage < totalPages - 1 && (
              <span className="px-3 py-1.5 text-sm text-gray-500 dark:text-gray-400">...</span>
            )}

            {totalPages > 5 && (
              <button
                onClick={() => setCurrentPage(totalPages)}
                className={`px-3 py-1.5 rounded-lg text-sm font-medium ${currentPage === totalPages
                  ? 'bg-primary text-white'
                  : 'bg-white dark:bg-gray-700 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-600'
                  }`}
              >
                {totalPages}
              </button>
            )}

            <button
              onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
              disabled={currentPage === totalPages}
              className="px-3 py-1.5 border border-gray-300 dark:border-gray-600 rounded-lg disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-100 dark:hover:bg-gray-700"
            >
              <i className="fas fa-chevron-right"></i>
            </button>
          </div>
        </div>
      )}

      {/* ===== BOUTONS BULK ACTIONS ===== */}
      {selectedDocuments.length > 0 && (
        <div className="mt-6 flex flex-col sm:flex-row sm:justify-end gap-3">
          <div className="flex flex-wrap gap-2">

            {/* ✅ BOUTON "CHANGER STATUT" - FONCTIONNEL */}
            <div className="relative">
              <button
                onClick={() => {
                  setStatusMenuOpen(!statusMenuOpen);
                  setAssigneeMenuOpen(false);
                }}
                className="px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-md text-sm flex items-center gap-2 transition-colors"
              >
                <i className="fas fa-exchange-alt"></i>
                Changer statut
                <i className={`fas fa-chevron-down text-xs ml-1 transition-transform ${statusMenuOpen ? 'rotate-180' : ''}`}></i>
              </button>

              {/* Menu déroulant des statuts */}
              {statusMenuOpen && (
                <div className="absolute right-0 mt-1 w-56 bg-white dark:bg-gray-800 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 py-1 z-50">
                  {documentStatuses.map(status => (
                    <button
                      key={status}
                      onClick={() => {
                        handleBulkStatusChange(status);
                        setStatusMenuOpen(false);
                      }}
                      className="w-full px-4 py-2 text-left hover:bg-gray-100 dark:hover:bg-gray-700 text-sm flex items-center gap-2"
                    >
                      <span className={`inline-block w-3 h-3 rounded-full ${statusClass(status).split(' ')[0].replace('text', 'bg')}`}></span>
                      {STATUS_LABELS[status]}
                    </button>
                  ))}
                </div>
              )}
            </div>

            {/* ✅ BOUTON "RÉASSIGNER" - FONCTIONNEL */}
            <div className="relative">
              <button
                onClick={() => {
                  setAssigneeMenuOpen(!assigneeMenuOpen);
                  setStatusMenuOpen(false);
                }}
                className="px-4 py-2 bg-purple-600 hover:bg-purple-700 text-white rounded-md text-sm flex items-center gap-2 transition-colors"
              >
                <i className="fas fa-user-edit"></i>
                Réassigner
                <i className={`fas fa-chevron-down text-xs ml-1 transition-transform ${assigneeMenuOpen ? 'rotate-180' : ''}`}></i>
              </button>

              {/* Menu déroulant des assignés */}
              {assigneeMenuOpen && (
                <div className="absolute right-0 mt-1 w-56 bg-white dark:bg-gray-800 rounded-lg shadow-lg border border-gray-200 dark:border-gray-700 py-1 z-50">
                  {assignees.map(assignee => (
                    <button
                      key={assignee}
                      onClick={() => {
                        handleBulkReassign(assignee);
                        setAssigneeMenuOpen(false);
                      }}
                      className="w-full px-4 py-2 text-left hover:bg-gray-100 dark:hover:bg-gray-700 text-sm flex items-center gap-2"
                    >
                      <i className="fas fa-user text-purple-500 mr-2"></i>
                      {assignee}
                    </button>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>
      )}

      {/* Modals */}
      {isModalOpen && (
        <>
          <div className="fixed inset-0 bg-black bg-opacity-50 z-50" onClick={closeModal}></div>
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl max-w-2xl w-full max-h-[90vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
              <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center">
                <h3 className="text-xl font-bold">
                  <i className={`fas ${editingDocument ? 'fa-edit' : 'fa-file-plus'} mr-2 text-primary`}></i>
                  {editingDocument ? `Modifier : ${editingDocument.title}` : 'Nouveau document'}
                </h3>
                <button onClick={closeModal} className="text-gray-400 hover:text-gray-600">
                  <i className="fas fa-times text-xl"></i>
                </button>
              </div>
              <form onSubmit={handleSubmit} className="p-6">
                {/* Titre */}
                <div className="mb-5">
                  <label htmlFor="doc-title" className="block text-sm font-medium mb-2">
                    Titre du document <span className="text-red-500">*</span>
                  </label>
                  <input
                    id="doc-title"
                    type="text"
                    value={newDocument.title}
                    onChange={(e) => {
                      setNewDocument({ ...newDocument, title: e.target.value });
                      if (formErrors.title) setFormErrors({ ...formErrors, title: false });
                    }}
                    className={`w-full px-4 py-2.5 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary ${formErrors.title ? 'border-red-500' : 'border-gray-300 dark:border-gray-600'
                      } dark:bg-gray-700 dark:text-white`}
                    required
                  />
                  {formErrors.title && <p className="mt-1 text-xs text-red-500">Le titre est requis</p>}
                </div>

                {/* Type et Source */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-5">
                  <div>
                    <label htmlFor="doc-type" className="block text-sm font-medium mb-2">Type de document</label>
                    <select
                      id="doc-type"
                      value={newDocument.type}
                      onChange={(e) => setNewDocument({ ...newDocument, type: e.target.value })}
                      className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white"
                    >
                      {documentTypes.map(type => <option key={type} value={type}>{type}</option>)}
                    </select>
                  </div>
                  <div>
                    <label htmlFor="doc-source" className="block text-sm font-medium mb-2">Source <span className="text-red-500">*</span></label>
                    <input
                      id="doc-source"
                      type="text"
                      value={newDocument.source}
                      onChange={(e) => {
                        setNewDocument({ ...newDocument, source: e.target.value });
                        if (formErrors.source) setFormErrors({ ...formErrors, source: false });
                      }}
                      className={`w-full px-4 py-2.5 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary ${formErrors.source ? 'border-red-500' : 'border-gray-300 dark:border-gray-600'
                        } dark:bg-gray-700 dark:text-white`}
                      required
                    />
                    {formErrors.source && <p className="mt-1 text-xs text-red-500">La source est requise</p>}
                  </div>
                </div>

                {/* Statut et Progression */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-5 mb-5">
                  <div>
                    <label htmlFor="doc-status" className="block text-sm font-medium mb-2">Statut éditorial</label>
                    <select
                      id="doc-status"
                      value={newDocument.status}
                      onChange={(e) => {
                        const value = e.target.value as DocumentStatus;
                        setNewDocument({
                          ...newDocument,
                          status: value,
                          workflow_step: getWorkflowStep(value),
                          progress: getWorkflowProgress(value)
                        });
                      }}
                      className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white"
                    >
                      {documentStatuses.map(status => (
                        <option key={status} value={status}>
                          {STATUS_LABELS[status]}
                        </option>
                      ))}
                    </select>
                  </div>
                  <div>
                    <label htmlFor="doc-progress" className="block text-sm font-medium mb-2">Progression (%)</label>
                    <input
                      id="doc-progress"
                      type="number"
                      min="0"
                      max="100"
                      value={newDocument.progress}
                      onChange={(e) => {
                        const v = parseInt(e.target.value) || 0;
                        setNewDocument({ ...newDocument, progress: Math.min(100, Math.max(0, v)) });
                      }}
                      className="w-full px-4 py-2.5 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white"
                    />
                  </div>
                </div>

                {/* Assignation */}
                <div className="mb-5">
                  <label htmlFor="doc-assigned" className="block text-sm font-medium mb-2">Assigné à <span className="text-red-500">*</span></label>
                  <select
                    id="doc-assigned"
                    value={newDocument.assigned_to}
                    onChange={(e) => {
                      setNewDocument({ ...newDocument, assigned_to: e.target.value });
                      if (formErrors.assigned_to) setFormErrors({ ...formErrors, assigned_to: false });
                    }}
                    className={`w-full px-4 py-2.5 border rounded-lg focus:outline-none focus:ring-2 focus:ring-primary ${formErrors.assigned_to ? 'border-red-500' : 'border-gray-300 dark:border-gray-600'
                      } dark:bg-gray-700 dark:text-white`}
                    required
                  >
                    <option value="">-- Sélectionner --</option>
                    {assignees.map(assignee => <option key={assignee} value={assignee}>{assignee}</option>)}
                  </select>
                  {formErrors.assigned_to && <p className="mt-1 text-xs text-red-500">Veuillez sélectionner</p>}
                </div>

                {/* Gestion des tags */}
                <div className="mb-6">
                  <label className="block text-sm font-medium mb-2">
                    Tags <span className="text-xs text-gray-500">(Entrée ou +)</span>
                  </label>
                  <div className="flex gap-2 mb-2">
                    <input
                      type="text"
                      value={tagsInput}
                      onChange={(e) => setTagsInput(e.target.value)}
                      onKeyPress={(e) => e.key === 'Enter' && (e.preventDefault(), handleAddTag())}
                      className="flex-1 px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary dark:bg-gray-700 dark:text-white"
                      placeholder="Ex: Volume 1, Yaoundé..."
                    />
                    <button type="button" onClick={handleAddTag} className="px-4 py-2 bg-primary hover:bg-primary-dark text-white rounded-lg">
                      +
                    </button>
                  </div>
                  <div className="flex flex-wrap gap-2">
                    {(newDocument.tags || []).map((tag, index) => (
                      <span key={index} className="px-3 py-1.5 bg-blue-100 dark:bg-blue-900/30 text-blue-800 dark:text-blue-200 rounded-full flex items-center gap-1">
                        #{tag}
                        <button type="button" onClick={() => handleRemoveTag(tag)} className="hover:text-blue-600">
                          <i className="fas fa-times text-xs"></i>
                        </button>
                      </span>
                    ))}
                  </div>
                </div>

                {/* Gestion des fichiers joints */}
                <div className="mb-6 pt-4 border-t border-gray-200 dark:border-gray-700">
                  <h4 className="text-sm font-medium text-gray-700 dark:text-gray-300 mb-3 flex items-center">
                    <i className="fas fa-paperclip mr-2 text-gray-500"></i>
                    Fichier attaché
                  </h4>
                  <FileUpload
                    documentId={editingDocument?.id || 'new'}
                    currentFileUrl={newDocument.file_url || null}
                    onFileUploaded={(url) => {
                      setNewDocument(prev => ({ ...prev, file_url: url }));
                    }}
                    onFileDeleted={() => {
                      setNewDocument(prev => ({ ...prev, file_url: '' }));
                    }}
                    maxFileSize={50 * 1024 * 1024}
                  />
                  {newDocument.file_url && (
                    <p className="mt-2 text-xs text-green-600 dark:text-green-400 flex items-center">
                      <i className="fas fa-check-circle mr-1.5"></i>
                      Fichier attaché : {decodeURIComponent(newDocument.file_url.split('/').pop() || '')}
                    </p>
                  )}
                </div>

                {/* Actions */}
                <div className="flex flex-col sm:flex-row sm:justify-end gap-3 pt-4 border-t border-gray-200 dark:border-gray-700">
                  <button type="button" onClick={closeModal} className="px-5 py-2.5 text-sm font-medium bg-gray-100 dark:bg-gray-700 hover:bg-gray-200 dark:hover:bg-gray-600 rounded-lg">
                    Annuler
                  </button>
                  <button type="submit" className="px-5 py-2.5 text-sm font-medium text-white bg-primary hover:bg-primary-dark rounded-lg flex items-center">
                    <i className={`fas ${editingDocument ? 'fa-save' : 'fa-plus'} mr-2`}></i>
                    {editingDocument ? 'Mettre à jour' : 'Créer le document'}
                  </button>
                </div>
              </form>
            </div>
          </div>
        </>
      )}

      {/* Modal historique */}
      {isHistoryModalOpen && selectedDocumentForHistory && (
        <>
          <div className="fixed inset-0 bg-black bg-opacity-50 z-50" onClick={closeHistoryModal}></div>
          <div className="fixed inset-0 z-50 flex items-center justify-center p-4">
            <div className="bg-white dark:bg-gray-800 rounded-xl shadow-2xl max-w-3xl w-full max-h-[90vh] overflow-y-auto" onClick={(e) => e.stopPropagation()}>
              <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center">
                <h3 className="text-xl font-bold"><i className="fas fa-history mr-2 text-amber-500"></i>Historique des versions</h3>
                <button onClick={closeHistoryModal} className="text-gray-400 hover:text-gray-600"><i className="fas fa-times text-xl"></i></button>
              </div>
              <div className="p-6">
                {documentVersions.length === 0 ? (
                  <div className="text-center py-8 text-gray-500 dark:text-gray-400">
                    <i className="fas fa-inbox text-4xl mb-3"></i>
                    <p>Aucune version antérieure</p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {documentVersions.map((version: any, index: number) => (
                      <div key={version.id} className="border border-gray-200 dark:border-gray-700 rounded-lg p-4 hover:bg-gray-50 dark:hover:bg-gray-700/50">
                        <div className="flex justify-between items-start mb-3">
                          <div>
                            <span className="px-2 py-1 text-xs font-medium bg-blue-100 text-blue-800 rounded">Version {version.version_number}</span>
                            <p className="text-sm text-gray-500 dark:text-gray-400 mt-1">{formatDateTime(version.created_at)}</p>
                          </div>
                          <div className="flex gap-2">
                            <button
                              onClick={() => handleCompareVersions(version)}
                              className="px-3 py-1.5 text-xs bg-amber-600 hover:bg-amber-700 text-white rounded-md flex items-center transition-colors"
                              title="Comparer avec la version précédente"
                              aria-label={`Comparer version ${version.version_number} avec la précédente`}
                            >
                              <i className="fas fa-code-compare mr-1"></i> Comparer
                            </button>
                            <button
                              onClick={() => handleRestoreVersion(version.id)}
                              className="px-3 py-1.5 text-xs bg-green-600 hover:bg-green-700 text-white rounded-md flex items-center transition-colors"
                              aria-label={`Restaurer version ${version.version_number}`}
                            >
                              <i className="fas fa-undo mr-1"></i> Restaurer
                            </button>
                          </div>
                        </div>
                        <div className="grid grid-cols-2 gap-3 text-sm">
                          <div><span className="font-medium">Titre :</span> {version.title}</div>
                          <div>
                            <span className="font-medium">Statut :</span>
                            <span className={`ml-1 px-2 py-0.5 rounded text-xs ${statusClass(version.status)}`}>
                              {STATUS_LABELS[version.status as DocumentStatus]}
                            </span>
                          </div>
                          <div><span className="font-medium">Progression :</span> {version.progress}%</div>
                          <div><span className="font-medium">Assigné à :</span> {version.assigned_to}</div>
                          <div className="col-span-2">
                            <span className="font-medium">Tags :</span>
                            <div className="flex flex-wrap gap-1 mt-1">
                              {version.tags.map((tag: string, i: number) => (
                                <span key={i} className="px-2 py-0.5 bg-gray-200 dark:bg-gray-600 text-xs rounded">#{tag}</span>
                              ))}
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </div>
          </div>
        </>
      )}

      {/* Diff viewer */}
      {diffViewerOpen && versionsToCompare && (
        <DiffViewer
          oldVersion={versionsToCompare.old}
          newVersion={versionsToCompare.new}
          onClose={() => {
            setDiffViewerOpen(false);
            setVersionsToCompare(null);
          }}
        />
      )}
    </div>
  );
};

export default Documents;
